from string_utils.manipulation import prettify

def test__prettify_non_string_input():
    """
    Test the prettify function with invalid input types, such as integers or lists. 
    This will check if the mutant can handle errors due to the invalid subtraction operation.
    """
    inputs = [123, ['list', 'of', 'words'], None, 45.67]

    for input_value in inputs:
        try:
            output = prettify(input_value)
            print(f"output for input {input_value}: '{output}'")
        except Exception as e:
            print(f"exception for input {input_value}: {str(e)}")
